import os, base64, json, datetime
tok = os.environ.get("KIYOTAKA_API_KEY","")
if not tok:
    print("kosong")
else:
    try:
        parts = tok.split(".")
        def b64d(s):
            s += "=" * (-len(s) % 4)
            return base64.urlsafe_b64decode(s)
        header = json.loads(b64d(parts[0]))
        payload = json.loads(b64d(parts[1]))
        print("Header:", json.dumps(header))
        print("Payload keys:", list(payload.keys()))
        for k in ("exp","iat","sub","iss","email","username"):
            if k in payload:
                v = payload[k]
                if k in ("exp","iat") and isinstance(v,(int,float)):
                    print(f"  {k}: {v} -> {datetime.datetime.utcfromtimestamp(v)} UTC")
                else:
                    print(f"  {k}: {v}")
    except Exception as e:
        print("decode error:", e)
